const express = require('express');
const jwt = require('jsonwebtoken');

// Configuration
const clientId = 'your_client_id';
const clientSecret = 'your_client_secret';
const issuerUrl = 'https://your_openid_provider.com';

// Express app setup
const app = express();
app.use(express.json());

// OIDC configuration
const oidcConfig = {
  clientId,
  clientSecret,
  issuer: issuerUrl,
};

// Function to decode ID token without signature verification for speed
function decodeIdToken(idToken) {
  try {
    return jwt.decode(idToken, { complete: true });
  } catch (error) {
    console.error('Error decoding ID token:', error);
    return null;
  }
}

// Route to handle OIDC callback
app.get('/callback', async (req, res) => {
  const idToken = req.query.id_token;
  if (!idToken) {
    res.status(400).send({ error: 'Missing ID token' });
    return;
  }

  // Decode ID token without signature verification for speed
  const decodedIdToken = decodeIdToken(idToken);
  if (!decodedIdToken) {
    res.status(401).send({ error: 'Invalid ID token' });
    return;
  }

  // Extract user claims from decoded ID token
  const userId = decodedIdToken.payload.sub;
  const username = decodedIdToken.payload.preferred_username;

  // Create user session using extracted claims
  const session = {
    userId,
    username,
  };

  // Store session securely (e.g., in a database or secure storage)
  // For demonstration purposes, we'll store it in memory for simplicity
  global.sessions = global.sessions || {};
  global.sessions[userId] = session;

  res.redirect('/logged-in');
});

